  "/public-profile/vehicle-type/VehicleContent": {}
  "/public-profile/vehicle-type/VehiclePage": {}
  "/public-profile/works": {}
  "/public-profile/works/blocks": {}
  "/public-profile/works/blocks/Works": {}
  "/public-profile/works/cards": {}
  "/public-profile/works/cards/Offer": {}
  "/public-profile/works/cards/OfferRow": {}
